                            )}
                        </m.div>

                        {/* Hook text ΓÇö line-by-line stagger */}
                        <div className="max-w-xl mx-auto w-full mb-12">
                            {(lesson.hook || lesson.description || "").split("\n").filter(Boolean).map((line: string, i: number) => (
                                <m.h2
